static PRINTED_MASK: AtomicU64 = AtomicU64::new(0);
const BOOT_WAIT_MAX_SPINS: usize = 20_000_000;

/// 把指定 hart 标记为已经完成启动输出。
fn mark_printed(hart_id: HartId) {
    PRINTED_MASK.fetch_or(HartMask::empty().insert(hart_id).bits(), Ordering::Release);
}

/// 等待目标 hart 集合都进入“已完成启动输出”状态。
///
/// 若在 `max_spins` 次自旋内全部到达，则返回当时观测到的完整位图；
/// 否则返回超时瞬间观测到的位图，供调用者继续判定。
#[inline]
fn wait_printed(mask: HartMask, max_spins: usize) -> HartMask {
    let want = mask.bits();
    for _ in 0..max_spins {
        let printed = PRINTED_MASK.load(Ordering::Acquire);
        if (printed & want) == want {
            return HartMask::from_bits(printed);
        }
        cpu::relax();
    }
    HartMask::from_bits(PRINTED_MASK.load(Ordering::Acquire))
}

